import{c as s,Q as t,j as i,m as l}from "./chunks/framework.NuazoUDF.js";const g=JSON.parse('{"title":"全栈项目搭建流程 - 从零到一的完整指南","description":"本文档主要讲解如何从零到一搭建自己的全栈项目，涵盖能力要求、技术栈、开发流程和实战经验","frontmatter":{"title":"全栈项目搭建流程 - 从零到一的完整指南","date":"2026-05-31T00:00:00.000Z","description":"本文档主要讲解如何从零到一搭建自己的全栈项目，涵盖能力要求、技术栈、开发流程和实战经验","tags":["全栈开发","项目搭建","AI辅助开发","后端开发","前端开发"],"author":"一行栗子"},"headers":[],"relativePath":"blog/fullstack-project-guide.md","filePath":"blog/fullstack-project-guide.md","lastUpdated":1780270810000}'),o={name:"blog/fullstack-project-guide.md"};function e(n, a, r, d, c, p){return t(),i("div",null,[...a[0]||(a[0]=[l(`<div class="hero-section"><div class="hero-content"><h1 class="hero-title">🚀 全栈项目搭建流程</h1><p class="hero-subtitle"> 从零到一搭建自己的全栈项目<br> 掌握核心能力，而非追逐技术栈 </p><div class="hero-badges"><span class="badge">🎯 能力驱动</span><span class="badge">💡 AI辅助</span><span class="badge">🔧 实战导向</span><span class="badge">📈 成长型项目</span></div></div></div><h2 id="核心理念" tabindex="-1">核心理念 <a class="header-anchor" href="#核心理念" aria-label="Permalink to &quot;核心理念&quot;">​</a></h2><div class="quote-box"><p>你多会几个技术栈没什么优势，真正值得称赞的是技术栈开发者本身。人家开源没收钱，再加上写的好，生怕你学不会。</p></div><p>掌握全栈的能力，不是让你掌握多少框架，而是你能进行<strong>通用客户端交互</strong>和<strong>业务接口封装</strong>。写完这些框架，它们就只是工具而已。</p><p>在AI辅助学习和项目明确需求的情况下，学习这些框架其实很简单。因为是<strong>自身业务需求驱动</strong>，理解也会很透彻。</p><h2 id="开发流程图" tabindex="-1">开发流程图 <a class="header-anchor" href="#开发流程图" aria-label="Permalink to &quot;开发流程图&quot;">​</a></h2><div class="concept-flow"><div class="flow-item">📝 概念原型</div><span class="arrow">→</span><div class="flow-item">🗄️ 设计数据库表</div><span class="arrow">→</span><div class="flow-item">📋 设计接口文档</div><span class="arrow">→</span><div class="flow-item">⚙️ 写后端接口</div><span class="arrow">→</span><div class="flow-item">🧪 调试后端接口</div><span class="arrow">→</span><div class="flow-item">🎨 写前端页面</div><span class="arrow">→</span><div class="flow-item">🔗 前后端联调</div></div><h3 id="迭代优化流程" tabindex="-1">迭代优化流程 <a class="header-anchor" href="#迭代优化流程" aria-label="Permalink to &quot;迭代优化流程&quot;">​</a></h3><p>开发过程中不可避免会遇到需求变更和设计问题：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[实现接口] --&gt; B{发现问题}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|需求变更| C[整合逻辑重新设计]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|初版设计问题| C</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[修改后端数据]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[修改前端数据]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; A</span></span></code></pre></div><h2 id="技术栈要求" tabindex="-1">技术栈要求 <a class="header-anchor" href="#技术栈要求" aria-label="Permalink to &quot;技术栈要求&quot;">​</a></h2><div class="tools-grid"><div class="tool-card"><div class="tool-name">后端技术栈</div><div class="tool-desc"> 你至少得会 <strong>Redis</strong>，这是高频使用的中间件。前期技术越扎实，后面要处理的&quot;屎山&quot;就越少。 </div><span class="tool-tag">Redis</span><span class="tool-tag">SpringBoot</span><span class="tool-tag">JWT</span></div><div class="tool-card"><div class="tool-name">前端技术栈</div><div class="tool-desc"> 这三个就够了：<strong>HbuilderX</strong> + <strong>uni_app</strong> + <strong>Trae</strong>。支持Web、H5、小程序多端运行。 </div><span class="tool-tag">HbuilderX</span><span class="tool-tag">uni_app</span><span class="tool-tag">Trae</span></div><div class="tool-card"><div class="tool-name">接口调试工具</div><div class="tool-desc"><strong>ApiFox</strong> 是必备的接口调试工具。按规划肯定会用到。后期涉及并发测试可以研究 <strong>JMeter</strong>。 </div><span class="tool-tag">ApiFox</span><span class="tool-tag">JMeter</span></div></div><h2 id="实战经验分享" tabindex="-1">实战经验分享 <a class="header-anchor" href="#实战经验分享" aria-label="Permalink to &quot;实战经验分享&quot;">​</a></h2><p>做自己的项目绝对是<strong>成长型的</strong>，东西都是根据需求学的。</p><h3 id="经验1-数据库表设计需要-蒸馏" tabindex="-1">经验1：数据库表设计需要&quot;蒸馏&quot; <a class="header-anchor" href="#经验1-数据库表设计需要-蒸馏" aria-label="Permalink to &quot;经验1：数据库表设计需要&quot;蒸馏&quot;&quot;">​</a></h3><div class="experience-card"><h4>📦 AI设计的初始表结构需要优化</h4><p>在最初版设计数据库时，AI建的字段比较庞大，只能说是最初模板。然后你要根据实际业务进行一次&quot;蒸馏&quot;。在实际代码开发中，你还会发现原本经过调整的表结构会有遗漏字段，需要有能力根据当前代码去修改。</p></div><h3 id="经验2-前端页面需要迭代" tabindex="-1">经验2：前端页面需要迭代 <a class="header-anchor" href="#经验2-前端页面需要迭代" aria-label="Permalink to &quot;经验2：前端页面需要迭代&quot;">​</a></h3><div class="experience-card"><h4>🎨 预留查询功能的空间</h4><p>最开始在设计前端页面时没考虑到加查询，后面发现确实需要整一个。然后你就需要写接口文档、新增接口、给数据库加索引（典例：游标查询、新建联合索引、优化查询速率）。</p></div><h3 id="经验3-要有重写的勇气" tabindex="-1">经验3：要有重写的勇气 <a class="header-anchor" href="#经验3-要有重写的勇气" aria-label="Permalink to &quot;经验3：要有重写的勇气&quot;">​</a></h3><div class="experience-card"><h4>🔄 推倒重建的勇气</h4><p>关于商品模块，学到后面会了解企业对于模糊查询是使用ES实现的。主页关于商品简单展示，可能需要把之前一大片推倒重建，重新写接口文档、改数据库、和前端交互、修改细节。</p></div><h3 id="经验4-拥抱重构" tabindex="-1">经验4：拥抱重构 <a class="header-anchor" href="#经验4-拥抱重构" aria-label="Permalink to &quot;经验4：拥抱重构&quot;">​</a></h3><div class="experience-card"><h4>🛠️ 项目结构的迭代</h4><p>项目初期水平不够，项目结构可能不好。也要有勇气重构文件，或者一点点补充重写之前的代码。需要有对自己项目的&quot;爱护之心&quot;。然后你也会理解什么是&quot;屎山代码的无力感&quot;。</p></div><h2 id="开发工具选择" tabindex="-1">开发工具选择 <a class="header-anchor" href="#开发工具选择" aria-label="Permalink to &quot;开发工具选择&quot;">​</a></h2><h3 id="产品原型参考" tabindex="-1">产品原型参考 <a class="header-anchor" href="#产品原型参考" aria-label="Permalink to &quot;产品原型参考&quot;">​</a></h3><p>你现在应该是在脑海里有个产品雏形：</p><table tabindex="0"><thead><tr><th>类别</th><th>参考产品</th></tr></thead><tbody><tr><td>电商类</td><td>淘宝、拼多多</td></tr><tr><td>通信类</td><td>微信、钉钉</td></tr><tr><td>视频类</td><td>抖音、B站</td></tr><tr><td>文字类</td><td>七猫、知乎</td></tr></tbody></table><h3 id="开发环境搭建" tabindex="-1">开发环境搭建 <a class="header-anchor" href="#开发环境搭建" aria-label="Permalink to &quot;开发环境搭建&quot;">​</a></h3><ol><li>新建一个项目，使用 <strong>Trae</strong> 打开 <strong>solo模式</strong>（vibecoding专属模式）</li><li>把需求告诉AI</li><li>建表是工程量很大的任务，需要不断细化需求或不断点击&quot;继续&quot;</li><li>这个过程很&quot;烧token&quot;，根据财力而定</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>实力不足的孩子们请打开你们的 <strong>Trae CN</strong>，使用国内免费模型。</p></div><h2 id="前端开发要点" tabindex="-1">前端开发要点 <a class="header-anchor" href="#前端开发要点" aria-label="Permalink to &quot;前端开发要点&quot;">​</a></h2><h3 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h3><p>你不需要精通前端的系统知识，但需要知道：</p><ul><li><strong>前端三剑客</strong>是指谁，分别是干什么的</li><li><strong>CSS</strong> 一些基础的格式</li><li>会看<strong>控制台日志</strong>，发给AI分析</li><li>会使用前端的<strong>开发者工具</strong>查看接口请求详情</li></ul><h3 id="css调参技巧" tabindex="-1">CSS调参技巧 <a class="header-anchor" href="#css调参技巧" aria-label="Permalink to &quot;CSS调参技巧&quot;">​</a></h3><p>比如前端你开发一个页面的卡片，AI做的一直忽大忽小、忽上忽下。此时你需要知道这只是CSS调一个参数的问题。CSS这参数是可以前端页面<strong>实时响应</strong>的，所以你会直接问AI，让他给你标记调参位置，然后你点击自己调。</p><h3 id="提示词编写方法" tabindex="-1">提示词编写方法 <a class="header-anchor" href="#提示词编写方法" aria-label="Permalink to &quot;提示词编写方法&quot;">​</a></h3><h4 id="前端排版" tabindex="-1">前端排版 <a class="header-anchor" href="#前端排版" aria-label="Permalink to &quot;前端排版&quot;">​</a></h4><p>如果你的模型是前沿模型（如 <strong>Gemini</strong>），可以直接把你设计的或者找到的产品原型截图发给AI，它可以直接按照这个排版去做前端设计。具体哪个卡片可能排版不满意，可以直接让AI帮你定位CSS调试位置。</p><h4 id="接口数据渲染提示词" tabindex="-1">接口数据渲染提示词 <a class="header-anchor" href="#接口数据渲染提示词" aria-label="Permalink to &quot;接口数据渲染提示词&quot;">​</a></h4><p>前端接口实现提示词构成：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>接口名称</span></span>
<span class="line"><span>接口位置</span></span>
<span class="line"><span>接口请求类型 + 请求参数</span></span>
<span class="line"><span>接口测试返回数据（ApiFox测试）</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">最佳实践</p><p>把测试响应数据粘贴发给AI，不用让AI去查接口文档。省token也省事！</p></div><h2 id="后端开发要点" tabindex="-1">后端开发要点 <a class="header-anchor" href="#后端开发要点" aria-label="Permalink to &quot;后端开发要点&quot;">​</a></h2><h3 id="安全框架选择" tabindex="-1">安全框架选择 <a class="header-anchor" href="#安全框架选择" aria-label="Permalink to &quot;安全框架选择&quot;">​</a></h3><p>新建一个 <strong>SpringBoot</strong> 项目后，实现安全校验模块。可以选择：</p><ul><li>Spring Security</li><li>Shiro</li><li>Sa-Token</li></ul><div class="warning custom-block"><p class="custom-block-title">建议</p><p>如果没学过，可以先用最简单的Spring自带的拦截器 + 自定义JWT实现。等到项目落地差不多了，再去换安全框架也没问题。</p></div><h3 id="安全模块集成" tabindex="-1">安全模块集成 <a class="header-anchor" href="#安全模块集成" aria-label="Permalink to &quot;安全模块集成&quot;">​</a></h3><ol><li>了解这些框架的优缺点，选一个</li><li>去知乎上找关于这个框架的文章（也可以问AI）</li><li>知道这个组件的<strong>核心概念</strong>、<strong>执行流程</strong></li><li>哪些地方需要你写业务代码，写的是什么</li><li>配置可以让AI帮你做，你只写业务嵌入</li></ol><h3 id="项目结构演进" tabindex="-1">项目结构演进 <a class="header-anchor" href="#项目结构演进" aria-label="Permalink to &quot;项目结构演进&quot;">​</a></h3><ul><li><strong>前期</strong>：项目规模小，传统 <strong>SpringMVC</strong> 就很不错</li><li><strong>后期</strong>：项目量大了，可能需要转为 <strong>DDD架构</strong></li><li>有些东西都是一点一点走，没办法一步升天</li></ul><div class="tip custom-block"><p class="custom-block-title">提醒</p><p>传统的SpringMVC留存率也很高，还是推荐一点点来。</p></div><h2 id="中间件引入策略" tabindex="-1">中间件引入策略 <a class="header-anchor" href="#中间件引入策略" aria-label="Permalink to &quot;中间件引入策略&quot;">​</a></h2><p>推荐<strong>按需选择</strong>。看一下你的具体业务需求：</p><ul><li>需要实现什么功能？</li><li>做什么优化？</li></ul><p>然后直接在基建包里加就行，去学习，与你的项目业务耦合，实现功能。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><div class="cta-section"><div class="cta-content"><h2>🎯 成为前端AI开发工程师</h2><p style="font-size:1.2rem;margin:1.5rem 0;"> 评判你好坏的是，你能不能按照需求把页面实现出来。<br> 具体你会什么代码，不重要。<br><strong style="font-size:1.5rem;">No body care.</strong></p><p style="color:rgba(255, 255, 255, 0.9);"> 真正值得称赞的是技术栈开发者本身，人家开源没收钱，再加上写的好，生怕你学不会。 </p></div></div><hr><p><strong>作者</strong>：一行栗子 | <strong>标签</strong>：全栈开发 · AI辅助 · 项目实战 · 能力驱动</p>`,60)])])}const u=s(o,[["render",e]]);export{g as __pageData,u as default};
